	}

	return entry, true
}

func comparablePath(path string) string {
	if path == "" {
		return ""
	}

	slash := strings.ReplaceAll(path, "\\", "/")
	if len(slash) >= 2 && slash[1] == ':' {
		return strings.ToLower(slash[:1]) + slash[1:]
	}

	return slash
}

